/**
 * Registry of AUTOGENERATED files — the heart of the "don't edit the artifact,
 * fix the source" rule.
 *
 * When a truth-check finds drift inside one of these files, hand-editing it is
 * worthless: the next regeneration overwrites the edit, and the drift comes
 * straight back. The fix is ALWAYS at the source (the live DB, the Python
 * backend's OpenAPI, the platform.deprecated_relations table). The orchestrator
 * reads this registry to:
 *   1. mark CodeFiles as generated (so reference-scanning checks can skip / re-route them), and
 *   2. attach a loud "REGENERATE THE SOURCE" banner to any finding whose location is generated.
 *
 * Add a generated artifact here the moment one is introduced — that is the whole
 * platform play: one registry, every guard and every agent reads it.
 */
import type { GeneratedInfo } from "./types";

interface Rule {
  /** Matches a repo-relative, posix-style path. */
  test: (relPath: string) => boolean;
  info: GeneratedInfo;
}

const exact =
  (...paths: string[]) =>
  (rel: string) =>
    paths.includes(rel);
const underDir =
  (dir: string) =>
  (rel: string) =>
    rel === dir || rel.startsWith(dir.endsWith("/") ? dir : dir + "/");

const RULES: Rule[] = [
  {
    // Supabase-generated Database types — the FE's entire schema assumption.
    test: exact("types/database.types.ts", "types/matrixDb.types.ts"),
    info: {
      label: "Supabase database types",
      source: "the live Supabase database (project txzxabzwovsujtloxrus)",
      regen: "pnpm db-types",
      why: "these types are generated 1:1 from the live DB schema — the database is the source of truth, not this file",
    },
  },
  {
    // Everything under types/python-generated/ comes from aidream's OpenAPI + models.
    test: underDir("types/python-generated"),
    info: {
      label: "Python backend API types",
      source: "the aidream Python backend's OpenAPI schema + stream-event/LLM-param models",
      regen: "pnpm sync-types",
      why: "these are generated from the Python backend's live OpenAPI — to change them you change the backend (aidream) and re-sync, never this file",
    },
  },
  {
    // Mirror of platform.deprecated_relations.
    test: exact("scripts/dead-relations.json"),
    info: {
      label: "dead-relations registry",
      source: "the platform.deprecated_relations table in the live DB",
      regen: "re-sync from platform.deprecated_relations (see the db-change skill)",
      why: "this JSON mirrors a DB table — the move is recorded in the database; this file just reflects it",
    },
  },
  {
    // Live-truth snapshot this very system pulls.
    test: exact("scripts/schema-check/current-schema.json"),
    info: {
      label: "live schema snapshot",
      source: "the live Supabase database (via public.schema_truth_snapshot())",
      regen: "pnpm check:schema:refresh",
      why: "this is a cached pull of the live DB — refresh it, never hand-edit it",
    },
  },
];

/** Returns generation metadata if `relPath` is an autogenerated artifact, else null. */
export function classifyGenerated(relPath: string): GeneratedInfo | null {
  const rel = relPath.replace(/\\/g, "/");
  for (const r of RULES) if (r.test(rel)) return r.info;
  return null;
}

/** True when the path is an autogenerated artifact. */
export function isGenerated(relPath: string): boolean {
  return classifyGenerated(relPath) !== null;
}
